<svg viewBox="0 0 700 420" xmlns="http://www.w3.org/2000/svg" style="width:100%;height:auto;background:#111113;border-radius:12px;border:1px solid rgba(255,255,255,.08);margin:20px 0">
  <text x="20" y="30" fill="#fafafa" font-size="16" font-weight="700" font-family="sans-serif">Expansión del Piloto de Stablecoins Minoristas en Japón</text>
  <text x="20" y="50" fill="#71717a" font-size="13" font-family="sans-serif">Enero-agosto de 2026, según pruebas de Netstars</text>
  <line x1="40" y1="80" x2="40" y2="360" stroke="#3f3f46" stroke-width="2"/>
  <circle cx="40" cy="90" r="7" fill="#38bdf8"/>
  <text x="60" y="86" fill="#e4e4e7" font-size="14" font-weight="700" font-family="sans-serif">Ene-feb — Prueba de USDC en Haneda</text>
  <text x="60" y="105" fill="#a1a1aa" font-size="13" font-family="sans-serif">Piloto pequeño dirigido a turistas extranjeros</text>
  <circle cx="40" cy="150" r="7" fill="#38bdf8"/>
